import{c as e,Q as a,j as o,m as d}from"./chunks/framework.B1f5Gm19.js";const u=JSON.parse('{"title":"更新日志","description":"","frontmatter":{"title":"更新日志"},"headers":[],"relativePath":"developer/changelog.md","filePath":"developer/changelog.md","lastUpdated":1779163937000}'),r={name:"developer/changelog.md"};function l(i,t,c,n,h,s){return a(),o("div",null,[...t[0]||(t[0]=[d('<h2 id="_0-10-6-bugfix" tabindex="-1">0.10.6-bugfix <a class="header-anchor" href="#_0-10-6-bugfix" aria-label="Permalink to &quot;0.10.6-bugfix&quot;">​</a></h2><p>本次更新基于 p4gefau1t/trojan-go-next v0.10.6，精选了安全性和稳定性修复。仅修 bug，不加功能，不改架构。</p><p>项目现由 <a href="https://github.com/corevx" target="_blank" rel="noreferrer">corevx</a> 维护，仓库迁移至 <a href="https://github.com/corevx/trojan-go-next-next" target="_blank" rel="noreferrer">corevx/trojan-go-next-next</a>。</p><h3 id="重要变更" tabindex="-1">重要变更 <a class="header-anchor" href="#重要变更" aria-label="Permalink to &quot;重要变更&quot;">​</a></h3><ul><li>Go 版本要求从 <strong>1.14</strong> 提升至 <strong>1.22</strong></li><li>所有 <code>io/ioutil</code> 调用已迁移至 <code>io</code> 和 <code>os</code> 包（Go 1.16+ 推荐做法）</li><li>新增 Docker 多阶段构建支持</li></ul><h3 id="安全性修复" tabindex="-1">安全性修复 <a class="header-anchor" href="#安全性修复" aria-label="Permalink to &quot;安全性修复&quot;">​</a></h3><table tabindex="0"><thead><tr><th>修复项</th><th>影响范围</th><th>详情</th></tr></thead><tbody><tr><td>加密私钥加载</td><td>服务端</td><td>修复 <code>x509.DecryptPEMBlock</code> 在 Go 1.22+ 不可用的问题，恢复加密私钥支持</td></tr><tr><td>私钥解密逻辑反转</td><td>服务端</td><td>原代码在解密成功时返回错误，导致加密私钥始终无法使用。现在解密失败时才报错</td></tr><tr><td>MySQL 用户删除</td><td>MySQL 模式</td><td><code>RowsAffected</code> 逻辑反转：原代码在 <code>err != nil</code> 时检查结果，现已修正为 <code>err == nil &amp;&amp; r == 0</code>。修复删除用户后仍可连接的问题（Issue #374）</td></tr></tbody></table><h3 id="稳定性修复" tabindex="-1">稳定性修复 <a class="header-anchor" href="#稳定性修复" aria-label="Permalink to &quot;稳定性修复&quot;">​</a></h3><table tabindex="0"><thead><tr><th>修复项</th><th>影响范围</th><th>详情</th></tr></thead><tbody><tr><td>Panic 恢复</td><td>服务端</td><td>在 trojan/tls/mux 三个 server 的连接处理 goroutine 中添加 <code>defer recover()</code>，防止单连接 panic 导致整个服务崩溃</td></tr><tr><td>非阻塞 Channel 发送</td><td>服务端</td><td>trojan/server.go 中 4 处 channel 发送改为 <code>select</code> 非阻塞模式，防止 channel 满时 goroutine 永久阻塞</td></tr><tr><td>Ticker 泄漏</td><td>服务端</td><td>tls/server.go <code>checkKeyPairLoop</code> 和 memory.go <code>speedUpdater</code> 中添加 <code>defer ticker.Stop()</code>，防止 goroutine 泄漏</td></tr></tbody></table><h3 id="功能性修复" tabindex="-1">功能性修复 <a class="header-anchor" href="#功能性修复" aria-label="Permalink to &quot;功能性修复&quot;">​</a></h3><table tabindex="0"><thead><tr><th>修复项</th><th>影响范围</th><th>详情</th></tr></thead><tbody><tr><td>限速 bug</td><td>API + 服务端</td><td>memory.go 中 <code>else if</code> 改为 <code>if</code>，使 recv 限速器独立于 send 限速器运行。修复通过 API 设定的限速不生效的问题（Issue #216）</td></tr><tr><td>SNI 错误消息</td><td>服务端</td><td>SNI 校验失败时的错误消息现在会显示证书的 DNSNames 列表，而不仅显示硬编码的 sni 字段，方便排查（Issue #531, PR #532）</td></tr></tbody></table><h3 id="性能优化" tabindex="-1">性能优化 <a class="header-anchor" href="#性能优化" aria-label="Permalink to &quot;性能优化&quot;">​</a></h3><table tabindex="0"><thead><tr><th>优化项</th><th>影响范围</th><th>详情</th></tr></thead><tbody><tr><td>sync.Pool</td><td>全局</td><td>proxy/proxy.go 中 UDP 包缓冲区使用 <code>sync.Pool</code> 复用，减少高频场景下的内存分配和 GC 压力</td></tr></tbody></table><h3 id="明确不包含的改动" tabindex="-1">明确不包含的改动 <a class="header-anchor" href="#明确不包含的改动" aria-label="Permalink to &quot;明确不包含的改动&quot;">​</a></h3><p>以下改动来自社区 fork，经评估存在破坏性，<strong>未合并</strong>：</p><ul><li><s>30s 硬编码超时</s> — 导致客户端 38 秒固定断流（Issue #73）</li><li><s>net.Dial 替换 underlay.DialConn</s> — 破坏隧道栈分层，WebSocket+TLS 失效</li><li><s>QUIC 隧道</s> — 新功能，非 bug fix</li><li><s>SQLite 持久化</s> — 新功能，依赖 CGO</li><li><s>Recorder 模块</s> — 新功能</li><li><s>X-Forwarded-For 注入</s> — 新功能</li></ul><h3 id="验证状态" tabindex="-1">验证状态 <a class="header-anchor" href="#验证状态" aria-label="Permalink to &quot;验证状态&quot;">​</a></h3><ul><li>编译：<code>make clean &amp;&amp; make</code> 通过</li><li>单元测试：24 个测试包全部通过（<code>go test -v ./...</code>）</li><li>集成测试：server + client SOCKS5 代理 HTTP 流量验证通过</li></ul>',18)])])}const g=e(r,[["render",l]]);export{u as __pageData,g as default};
